setup_files.existing-schema.sql:
-- Current schema before migration
create table if not exists public.users (
  id bigserial primary key,
  email text unique not null,
  name text,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null,
  updated_at timestamp with time zone default timezone('utc'::text, now()) not null
);

create table if not exists public.posts (
  id bigserial primary key,
  user_id bigint references public.users(id) on delete cascade,
  title text not null,
  content text,
  published boolean default false,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

create table if not exists public.comments (
  id bigserial primary key,
  post_id bigint references public.posts(id) on delete cascade,
  user_id bigint references public.users(id) on delete cascade,
  content text not null,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

-- Add indexes for performance
create index idx_posts_user_id on public.posts(user_id);
create index idx_comments_post_id on public.comments(post_id);
create index idx_comments_user_id on public.comments(user_id);

setup_files.test-migration.sql:
-- Test cases for migration validation
-- Run these after migration to verify correctness

-- Test 1: Verify users table still exists with original columns
select id, email, name, created_at from public.users limit 1;

-- Test 2: Verify new role column exists and has correct default
select column_name, is_nullable, column_default from information_schema.columns
where table_name = 'users' and column_name = 'role';

-- Test 3: Verify permissions table created
select count(*) as permissions_count from public.permissions;

-- Test 4: Verify role_permissions table exists and has data
select count(*) as role_perms_count from public.role_permissions;

-- Test 5: Verify RLS is enabled
select schemaname, tablename, rowsecurity from pg_tables
where tablename in ('users', 'posts', 'comments')
order by tablename;

-- Test 6: Verify audit log table exists
select count(*) from information_schema.tables
where table_name = 'role_audit_log';

-- Test 7: Verify existing posts still reference their users
select count(*) from public.posts where user_id is not null
and user_id not in (select id from public.users);
-- Expected result: 0 (no orphaned posts)

-- Test 8: Verify existing comments still reference valid posts
select count(*) from public.comments where post_id is not null
and post_id not in (select id from public.posts);
-- Expected result: 0 (no orphaned comments)
